using System.Security.Cryptography;
using System.Text;
using System.Text.Json;

namespace Payments;

/// <summary>
/// Abstraction over an external payment provider (e.g. Stripe, Braintree).
/// </summary>
public interface IPaymentProvider
{
    Task<ProviderChargeResult> CreateChargeAsync(string cardToken, decimal amount);
    Task<ProviderRefundResult> CreateRefundAsync(string chargeId);
}

public record ProviderChargeResult(string Id, bool Succeeded, string? ErrorMessage = null);
public record ProviderRefundResult(string Id, bool Succeeded, string? ErrorMessage = null);

public record ChargeResult(string ChargeId, bool Success, string? ErrorMessage = null);
public record RefundResult(string RefundId, bool Success, string? ErrorMessage = null);

public record WebhookEvent(string Type, string ChargeId, string Status);
public record WebhookResult(bool Processed, string? EventType = null, string? Error = null);

public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;
    private readonly string _webhookSecret;

    public const decimal MaxChargeAmount = 999_999.99m;
    public const decimal MinChargeAmount = 0.50m;

    public PaymentGateway(IPaymentProvider provider, string webhookSecret)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));

        if (string.IsNullOrWhiteSpace(webhookSecret))
            throw new ArgumentException("Webhook secret is required.", nameof(webhookSecret));

        _webhookSecret = webhookSecret;
    }

    /// <summary>
    /// Charges a card token for the specified amount.
    /// </summary>
    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));

        if (amount < MinChargeAmount)
            throw new ArgumentOutOfRangeException(nameof(amount),
                $"Amount must be at least {MinChargeAmount:C}.");

        if (amount > MaxChargeAmount)
            throw new ArgumentOutOfRangeException(nameof(amount),
                $"Amount must not exceed {MaxChargeAmount:C}.");

        var result = await _provider.CreateChargeAsync(cardToken, amount);
        return new ChargeResult(result.Id, result.Succeeded, result.ErrorMessage);
    }

    /// <summary>
    /// Refunds a previously successful charge.
    /// </summary>
    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));

        var result = await _provider.CreateRefundAsync(chargeId);
        return new RefundResult(result.Id, result.Succeeded, result.ErrorMessage);
    }

    /// <summary>
    /// Validates and processes an incoming webhook payload.
    /// </summary>
    public WebhookResult ProcessWebhook(string payload, string signature)
    {
        if (string.IsNullOrWhiteSpace(payload))
            return new WebhookResult(false, Error: "Empty payload.");

        if (string.IsNullOrWhiteSpace(signature))
            return new WebhookResult(false, Error: "Missing signature.");

        var expectedSignature = ComputeSignature(payload);
        if (!CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(signature),
                Encoding.UTF8.GetBytes(expectedSignature)))
        {
            return new WebhookResult(false, Error: "Invalid signature.");
        }

        try
        {
            var evt = JsonSerializer.Deserialize<WebhookEvent>(payload,
                new JsonSerializerOptions { PropertyNameCaseInsensitive = true });

            if (evt is null || string.IsNullOrWhiteSpace(evt.Type))
                return new WebhookResult(false, Error: "Malformed event.");

            return new WebhookResult(true, EventType: evt.Type);
        }
        catch (JsonException)
        {
            return new WebhookResult(false, Error: "Invalid JSON.");
        }
    }

    /// <summary>
    /// Computes an HMAC-SHA256 signature for the given payload.
    /// Exposed internally so tests can generate valid signatures.
    /// </summary>
    internal string ComputeSignature(string payload)
    {
        var key = Encoding.UTF8.GetBytes(_webhookSecret);
        var data = Encoding.UTF8.GetBytes(payload);
        var hash = HMACSHA256.HashData(key, data);
        return Convert.ToHexStringLower(hash);
    }
}

