[TestClass]
public class ChargeAsyncTests
{
    private readonly Mock<IPaymentProvider> _providerMock = new();
    private readonly PaymentGateway _gateway;

    public ChargeAsyncTests()
    {
        _gateway = new PaymentGateway(_providerMock.Object, "test-secret");
    }

    // ── Validation ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(0.49)]
    public async Task ChargeAsync_AmountBelowMinimum_ThrowsArgumentOutOfRangeException(double amt)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amt));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountAboveMaximum_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", PaymentGateway.MaxChargeAmount + 0.01m));
    }

    // ── Boundary values ─────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ExactMinimumAmount_Succeeds()
    {
        _providerMock.Setup(p => p.CreateChargeAsync("tok_ok", PaymentGateway.MinChargeAmount))
            .ReturnsAsync(new ProviderChargeResult("ch_1", true));

        var result = await _gateway.ChargeAsync("tok_ok", PaymentGateway.MinChargeAmount);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_1", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ExactMaximumAmount_Succeeds()
    {
        _providerMock.Setup(p => p.CreateChargeAsync("tok_ok", PaymentGateway.MaxChargeAmount))
            .ReturnsAsync(new ProviderChargeResult("ch_max", true));

        var result = await _gateway.ChargeAsync("tok_ok", PaymentGateway.MaxChargeAmount);

        Assert.IsTrue(result.Success);
    }

    // ── Provider success / failure ──────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ProviderSucceeds_ReturnsSuccessResult()
    {
        _providerMock.Setup(p => p.CreateChargeAsync("tok_abc", 25.00m))
            .ReturnsAsync(new ProviderChargeResult("ch_123", true));

        var result = await _gateway.ChargeAsync("tok_abc", 25.00m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsNull(result.ErrorMessage);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderDeclines_ReturnsFailureWithMessage()
    {
        _providerMock.Setup(p => p.CreateChargeAsync("tok_bad", 50.00m))
            .ReturnsAsync(new ProviderChargeResult("ch_fail", false, "Card declined"));

        var result = await _gateway.ChargeAsync("tok_bad", 50.00m);

        Assert.IsFalse(result.Success);
        Assert.AreEqual("Card declined", result.ErrorMessage);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock.Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new HttpRequestException("Network error"));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _gateway.ChargeAsync("tok_x", 10m));
    }

    // ── Provider interaction verification ───────────────────────

    [TestMethod]
    public async Task ChargeAsync_PassesExactTokenAndAmountToProvider()
    {
        _providerMock.Setup(p => p.CreateChargeAsync("tok_precise", 77.77m))
            .ReturnsAsync(new ProviderChargeResult("ch_p", true))
            .Verifiable();

        await _gateway.ChargeAsync("tok_precise", 77.77m);

        _providerMock.Verify(p => p.CreateChargeAsync("tok_precise", 77.77m), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_InvalidToken_DoesNotCallProvider()
    {
        try { await _gateway.ChargeAsync("", 10m); } catch { }

        _providerMock.Verify(
            p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()), Times.Never);
    }
}

