[TestClass]
public class ProcessWebhookTests
{
    private const string Secret = "whsec_test_secret";
    private readonly PaymentGateway _gateway;

    public ProcessWebhookTests()
    {
        _gateway = new PaymentGateway(new Mock<IPaymentProvider>().Object, Secret);
    }

    private string Sign(string payload) => _gateway.ComputeSignature(payload);

    // ── Input validation ────────────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_EmptyPayload_ReturnsError(string? payload)
    {
        var result = _gateway.ProcessWebhook(payload!, "sig");

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Empty payload.", result.Error);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_MissingSignature_ReturnsError(string? sig)
    {
        var result = _gateway.ProcessWebhook("{}", sig!);

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Missing signature.", result.Error);
    }

    // ── Signature verification ──────────────────────────────────

    [TestMethod]
    public void ProcessWebhook_InvalidSignature_ReturnsError()
    {
        var payload = BuildPayload("charge.succeeded", "ch_1", "paid");

        var result = _gateway.ProcessWebhook(payload, "bad_signature");

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Invalid signature.", result.Error);
    }

    [TestMethod]
    public void ProcessWebhook_TamperedPayload_ReturnsError()
    {
        var originalPayload = BuildPayload("charge.succeeded", "ch_1", "paid");
        var signature = Sign(originalPayload);
        var tamperedPayload = BuildPayload("charge.succeeded", "ch_hacked", "paid");

        var result = _gateway.ProcessWebhook(tamperedPayload, signature);

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Invalid signature.", result.Error);
    }

    // ── Valid payloads ──────────────────────────────────────────

    [TestMethod]
    public void ProcessWebhook_ValidChargeSucceeded_ReturnsProcessed()
    {
        var payload = BuildPayload("charge.succeeded", "ch_42", "paid");
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsTrue(result.Processed);
        Assert.AreEqual("charge.succeeded", result.EventType);
        Assert.IsNull(result.Error);
    }

    [TestMethod]
    public void ProcessWebhook_ValidChargeFailed_ReturnsProcessed()
    {
        var payload = BuildPayload("charge.failed", "ch_99", "failed");
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsTrue(result.Processed);
        Assert.AreEqual("charge.failed", result.EventType);
    }

    [TestMethod]
    public void ProcessWebhook_ValidRefundCreated_ReturnsProcessed()
    {
        var payload = BuildPayload("refund.created", "ch_50", "refunded");
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsTrue(result.Processed);
        Assert.AreEqual("refund.created", result.EventType);
    }

    // ── Malformed payloads ──────────────────────────────────────

    [TestMethod]
    public void ProcessWebhook_InvalidJson_ReturnsError()
    {
        var payload = "not-json{{{";
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Invalid JSON.", result.Error);
    }

    [TestMethod]
    public void ProcessWebhook_MissingEventType_ReturnsError()
    {
        var payload = JsonSerializer.Serialize(new { ChargeId = "ch_1", Status = "paid" });
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Malformed event.", result.Error);
    }

    [TestMethod]
    public void ProcessWebhook_EmptyEventType_ReturnsError()
    {
        var payload = BuildPayload("", "ch_1", "paid");
        var sig = Sign(payload);

        var result = _gateway.ProcessWebhook(payload, sig);

        Assert.IsFalse(result.Processed);
        Assert.AreEqual("Malformed event.", result.Error);
    }

    // ── Helper ──────────────────────────────────────────────────

    private static string BuildPayload(string type, string chargeId, string status) =>
        JsonSerializer.Serialize(new WebhookEvent(type, chargeId, status));
}

